import { IMessageComposer } from '@nitrots/nitro-renderer';

export class AcceptItemOfferComposer implements IMessageComposer<any[]> {
    private _data: any[];

    // FIRST ARG MUST BE THE SELLER ID FROM THE POPUP (parser.senderId)
    constructor(sellerId: number, accepted: boolean) {
        this._data = [sellerId, accepted];
        console.log('[📤] AcceptItemOfferComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }
    public dispose(): void {}
}
